import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_returnsCSVParser() throws IOException {
        Reader reader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op
                })) {
            CSVParser parser = csvFormat.parse(reader);

            assertNotNull(parser);
            assertTrue(mocked.constructed().contains(parser));
        }
    }

    @Test
    void testParse_withNullReader_throwsNullPointerException() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParse_withCustomCSVFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.DEFAULT.withDelimiter(';').withQuote('"');
        Reader reader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = mockConstruction(CSVParser.class)) {
            CSVParser parser = customFormat.parse(reader);

            assertNotNull(parser);
            assertTrue(mocked.constructed().contains(parser));
        }
    }

    @Test
    void testParse_invokesCSVParserConstructor() throws IOException {
        Reader reader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = mockConstruction(CSVParser.class)) {
            CSVParser parser = csvFormat.parse(reader);

            // Verify that CSVParser constructor was called with correct arguments
            assertNotNull(parser);
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(parser, constructedParser);
        }
    }
}
